Sure! Here's an example of a Lambda function written in Node.js that accepts an uploaded CSV file:

```javascript
const AWS = require('aws-sdk');
const s3 = new AWS.S3();

exports.handler = async (event) => {
    const bucketName = '<your-bucket-name>'; // Update with your S3 bucket name

    try {
        const fileObject = event.Records[0].s3;
        const fileName = fileObject.object.key;

        // Retrieve the uploaded file from S3
        const data = await s3.getObject({ Bucket: bucketName, Key: fileName }).promise();
        const csvData = data.Body.toString('utf-8');

        // Process the CSV data here
        // Example: Parse and print the CSV as JSON
        const parsedData = parseCSV(csvData);
        console.log(parsedData);

        return {
            statusCode: 200,
            body: 'CSV file uploaded and processed successfully!',
        };
    } catch (error) {
        console.error(error);
        return {
            statusCode: 500,
            body: 'Error processing CSV file',
        };
    }
};

function parseCSV(csvData) {
    // Implement your custom CSV parsing logic here
    // This is just a simple example to convert CSV to JSON

    const lines = csvData.split('\n');
    const headers = lines[0].split(',');
    const result = [];

    for (let i = 1; i < lines.length; i++) {
        const obj = {};
        const currentline = lines[i].split(',');

        for (let j = 0; j < headers.length; j++) {
            obj[headers[j]] = currentline[j];
        }

        result.push(obj);
    }

    return JSON.stringify(result);
}
```

